All methods in `service` will be moved into separate files (`user.go`, `order.go`, `perm.go`, `helpers.go`) so that no file exceeds 150 lines, while the public API (`NewUserOrderService` and all exported methods) stays unchanged.  

```bash
# Create new packages and split service code
mkdir -p validation notification

# validation/validator.go – default validator implementation
cat > validation/validator.go <<'EOF'
package validation

import (
	"errors"
	"fmt"
	"strings"

	"refactor/types"
)

// Validator defines validation behaviours used by the service.
type Validator interface {
	ValidateEmail(email string) error
	ValidateOrder(items []types.OrderItem) error
}

// DefaultValidator implements Validator using the service configuration.
type DefaultValidator struct {
	EmailDomain string
	MaxItems    int
}

// ValidateEmail checks the format of an email address.
func (v *DefaultValidator) ValidateEmail(email string) error {
	if email == "" {
		return errors.New("email is required")
	}
	if !strings.Contains(email, "@") {
		return errors.New("email must contain @")
	}
	parts := strings.Split(email, "@")
	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
		return errors.New("email format is invalid")
	}
	if !strings.Contains(parts[1], ".") {
		return errors.New("email domain must contain a dot")
	}
	if v.EmailDomain != "" && parts[1] != v.EmailDomain {
		return fmt.Errorf("email must be from domain %s", v.EmailDomain)
	}
	return nil
}

// ValidateOrder checks that order items are well‑formed and respect limits.
func (v *DefaultValidator) ValidateOrder(items []types.OrderItem) error {
	if len(items) == 0 {
		return errors.New("order must have at least one item")
	}
	if len(items) > v.MaxItems {
		return fmt.Errorf("order cannot exceed %d items", v.MaxItems)
	}
	for i, item := range items {
		if item.ProductID == "" {
			return fmt.Errorf("item %d: product ID is required", i)
		}
		if item.Price < 0 {
			return fmt.Errorf("item %d: price cannot be negative", i)
		}
		if item.Quantity <= 0 {
			return fmt.Errorf("item %d: quantity must be positive", i)
		}
	}
	return nil
}
EOF

