package notification

import "refactor/types"

// Notifier abstracts how notifications are delivered.
type Notifier interface {
	// Append adds a notification to the provided slice.
	Append(dst *[]types.Notification, n types.Notification)
}

// SimpleNotifier stores notifications in‑memory.
type SimpleNotifier struct{}

// Append implements Notifier by appending to the slice.
func (s *SimpleNotifier) Append(dst *[]types.Notification, n types.Notification) {
	*dst = append(*dst, n)
}
EOF

