package service

import (
	"sync"

	"refactor/types"
	"refactor/validation"
	"refactor/notification"
)

// UserOrderService is the façade for all business operations.
type UserOrderService struct {
	mu            sync.RWMutex
	users         map[string]*types.User
	orders        map[string]*types.Order
	notifications []types.Notification

	userCounter   int
	orderCounter  int
	emailDomain   string
	maxItems      int
	adminRoles    []string

	validator validation.Validator
	notifier  notification.Notifier
}

// NewUserOrderService creates a service with default validator and notifier.
