	s := &UserOrderService{
		users:         make(map[string]*types.User),
		orders:        make(map[string]*types.Order),
		notifications: make([]types.Notification, 0),
		emailDomain:   "",
		maxItems:      100,
		adminRoles:    []string{"admin", "superadmin"},
	}
	// inject default implementations
	s.validator = &validation.DefaultValidator{EmailDomain: s.emailDomain, MaxItems: s.maxItems}
	s.notifier = &notification.SimpleNotifier{}
	return s
