package service

import (
	"fmt"
	"time"

	"refactor/types"
)

// CreateOrder validates, stores the order and sends a confirmation notice.
func (s *UserOrderService) CreateOrder(userID string, items []types.OrderItem) (*types.Order, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	// ensure user exists
	if _, ok := s.users[userID]; !ok {
		return nil, fmt.Errorf("user %s not found", userID)
	}
	// delegate order validation
	if err := s.validator.ValidateOrder(items); err != nil {
		return nil, err
	}
	// compute total
	var total float64
	for _, it := range items {
		total += it.Price * float64(it.Quantity)
	}
	s.orderCounter++
	order := &types.Order{
		ID:        fmt.Sprintf("order-%d", s.orderCounter),
		UserID:    userID,
		Items:     items,
		Status:    "active",
		Total:     total,
		CreatedAt: time.Now().Format(time.RFC3339),
	}
	s.orders[order.ID] = order

	// build and send confirmation notification
	lines := ""
	for _, it := range items {
		lines += fmt.Sprintf("  - %s (x%d): $%.2f\n", it.Name, it.Quantity, it.Price*float64(it.Quantity))
	}
	subject := fmt.Sprintf("Order %s confirmed", order.ID)
	body := fmt.Sprintf("Hi %s,\n\nYour order %s has been confirmed.\n\nItems:\n%s\nTotal: $%.2f\n\nThank you for your purchase!", s.users[userID].Name, order.ID, lines, total)
	s.notifier.Append(&s.notifications, types.Notification{
		To:      s.users[userID].Email,
		Subject: subject,
		Body:    body,
	})
	return order, nil
}

// GetOrder fetches an order by its ID.
func (s *UserOrderService) GetOrder(id string) (*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	order, ok := s.orders[id]
	if !ok {
		return nil, fmt.Errorf("order %s not found", id)
	}
	return order, nil
}

// ListOrdersByUser returns all orders belonging to a user.
func (s *UserOrderService) ListOrdersByUser(userID string) ([]*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	if _, ok := s.users[userID]; !ok {
		return nil, fmt.Errorf("user %s not found", userID)
	}
	var res []*types.Order
	for _, o := range s.orders {
		if o.UserID == userID {
			res = append(res, o)
		}
	}
	return res, nil
}

// CancelOrder cancels an order if the requester is owner or admin and sends a notice.
func (s *UserOrderService) CancelOrder(orderID, cancelledByUserID string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	order, ok := s.orders[orderID]
	if !ok {
		return fmt.Errorf("order %s not found", orderID)
	}
	if order.Status == "cancelled" {
		return errors.New("order is already cancelled")
	}
	user, ok := s.users[cancelledByUserID]
	if !ok {
		return fmt.Errorf("user %s not found", cancelledByUserID)
	}
	isAdmin := false
	for _, r := range s.adminRoles {
		if user.Role == r {
			isAdmin = true
			break
		}
	}
	if !isAdmin && order.UserID != cancelledByUserID {
		return errors.New("permission denied: only order owner or admin can cancel")
	}
	order.Status = "cancelled"

	owner, exists := s.users[order.UserID]
	if exists {
		subject := fmt.Sprintf("Order %s cancelled", orderID)
		body := fmt.Sprintf("Hi %s,\n\nYour order %s has been cancelled.\n\nIf you did not request this, please contact support.\n\nBest regards,\nThe Team", owner.Name, orderID)
		s.notifier.Append(&s.notifications, types.Notification{
			To:      owner.Email,
			Subject: subject,
			Body:    body,
		})
	}
	return nil
}

// CalculateTotal is a helper retained for compatibility.
func (s *UserOrderService) CalculateTotal(items []types.OrderItem) float64 {
	var total float64
	for _, it := range items {
		total += it.Price * float64(it.Quantity)
	}
	return total
}
EOF

